VALUES
  ('dietitian-moex-10434', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '利用功能性社會支持模式（functional social support）進行營養教育計劃介入時，常用的支持方式不包括：', '["情緒支持（emotional support）", "器具支持（instrumental support）", "健康支持（health support）", "資訊支持（informational support）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10435', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '抽菸男性其肺癌危險的勝算比（odds ratio）為6.5（95%信賴區間2.1~15.7），意指：', '["抽菸男性與未抽菸男性得到肺癌的危險性是獨立的", "抽菸男性比起未抽菸男性得到肺癌的危險性是顯著增加的", "抽菸男性比起未抽菸男性得到肺癌的危險性是顯著降低的", "無法判斷"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10436', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '蘇先生經醫師診斷並證實為肺癌第二期的患者，病歷顯示他一天至少抽4包菸，此評估方法的：', '["效度（validity）高", "敏感度（sensitivity）高", "準確度（accuracy）高", "特異性（specificity）高"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10437', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '當腸病毒感染進入高峰期前，衛生單位開始採取一些措施以防止病情的蔓延及擴散，此階段的預防措施為：', '["促進健康", "特殊防護", "早期診斷和適當治療", "限制殘障"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10438', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '從一世代研究中將已發病及健康的受試者分別列為病歷組及對照組並做進一步的流行病學研究，此研究法稱之為：', '["病歷對照研究（case control study）", "重疊病歷對照研究（nested case control study）", "世代研究（cohort study）", "介入研究（intervention study）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10439', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '「台灣地區老人營養健康狀況變遷調查1999–2000」所使用的營養調查方法與那一次的國民營養調查相同？', '["第一次", "第二次", "第三次", "以上皆非"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10440', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '比較「第一次國民營養健康狀況變遷調查 1993–1996」與「台灣地區老人營養健康狀況變遷調查 1999–2000」的抽樣設計，何者 敘述錯誤？', '["「台灣地區老人營養健康狀況變遷調查1999–2000」共將台灣地區分成13層", "「台灣地區老人營養健康狀況變遷調查1999–2000」設計採分層隨機集束取樣法", "「台灣地區老人營養健康狀況變遷調查1999–2000」以「戶」為單位採集體抽樣", "「第一次國民營養健康狀況變遷調查1993–1996」以9個年齡層進行取樣"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10441', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '與衛生、營養相關之國際機構不包括：', '["世界衛生組織（WHO）", "食物及農業組織（FAO）", "國際紅十字會", "國際扶輪社"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10442', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '美國農業部（USDA）用以監控居民食物攝取型態的改變，並確認需要進行營養教育及健康促進計劃族群的評估工具為：', '["飲食質量指標（diet quality index）", "健康飲食指標（healthy eating index）", "營養質量指標（nutritional quality index）", "飲食指南（dietary guidelines）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10443', 'dietitian', 'dietitian-moex-094-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '2005年美國新出版的「new food pyramid」與舊的食物金字塔的差別不包括：', '["新金字塔加入一個正在爬樓梯的人在金字塔的左邊", "新金字塔的食物種類由左至右以多個小三角型排列", "新金字塔沒有建議不同食物的攝取比例", "新的金字塔建議每日運動30分鐘"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "c8a56f98cde2", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "094130", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "094", "exam_name": "094年第二次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
